+    fn object_id_from_u64(raw: u64) -> ObjectId {
+        let mut bytes = [0_u8; 16];
+        bytes[0..8].copy_from_slice(&raw.to_le_bytes());
+        bytes[8..16].copy_from_slice(&raw.to_le_bytes());
+        ObjectId::from_bytes(bytes)
+    }
